// Purpose: Lightweight personal Telegram rules manager for Shiny Gmail.
// V2.6: Added /unreceipt, /unreview. Dynamic help text for domain vs sender commands.
const update = $input.first()?.json || {};
const message = update.message || update;
const chat = message.chat || {};
const from = message.from || {};
const account = $env.GMAIL_ACCOUNT || 'primary';
const allowedChatId = String($env.TELEGRAM_CHAT_ID || '');
const chatId = String(chat.id || message.chat_id || '');
const chatType = String(chat.type || 'private');
const allowGroups = String($env.TELEGRAM_ALLOW_GROUP_RULES || 'false') === 'true';
const telegramUserId = String(from.id || '');
const telegramUsername = from.username || '';
const text = String(message.text || '').trim();
function out(extra) { return [{ json: { account, chatId, chatType, telegramUserId, telegramUsername, rawText: text, ...extra } }]; }
if (!allowedChatId) return out({ allowed: false, action: 'reply', replyText: '\ud83d\udea8 TELEGRAM_CHAT_ID is missing. Rules Manager is locked.' });
if (chatId !== allowedChatId) return out({ allowed: false, action: 'reply', replyText: '\u26d4 Unauthorized.' });
if (chatType !== 'private' && !allowGroups) return out({ allowed: false, action: 'reply', replyText: '\u26d4 Rules Manager only accepts private chat commands.' });
if (!text) return out({ allowed: true, action: 'reply', replyText: 'Send /help for commands.' });
const parts = text.split(/\s+/);
const command = String(parts[0] || '').toLowerCase();
const value = String(parts[1] || '').toLowerCase().trim();
const validEmail = /^[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$/i;
const validDomain = /^[a-z0-9.-]+\.[a-z]{2,}$/i;
const helpText = '\ud83e\uddf9 Shiny Gmail Manager\n\n' +
  '<b>Sender rules</b> (e.g. mail@example.com)\n' +
  '/whitelist \u2192 priority\n' +
  '/blacklist \u2192 unimportant\n' +
  '/receipt \u2192 receipts\n' +
  '/review \u2192 please-review\n' +
  '/unwhitelist /unblacklist /unreceipt /unreview\n\n' +
  '<b>Domain rules</b> (e.g. example.com)\n' +
  '/whitelistdomain \u2192 priority\n' +
  '/blacklistdomain \u2192 unimportant\n' +
  '/unwhitelistdomain /unblacklistdomain\n\n' +
  '<b>View</b>\n/rules';
if (command === '/help' || command === '/start') return out({ allowed: true, action: 'help', replyText: helpText });
if (command === '/rules') return out({ allowed: true, action: 'list' });
const upsertMap = {
  '/whitelist': { ruleType: 'whitelist', matchType: 'exact_sender', priority: 10 },
  '/blacklist': { ruleType: 'blacklist', matchType: 'exact_sender', priority: 10 },
  '/receipt': { ruleType: 'force_receipts', matchType: 'exact_sender', priority: 10 },
  '/review': { ruleType: 'force_review', matchType: 'exact_sender', priority: 10 },
  '/whitelistdomain': { ruleType: 'whitelist', matchType: 'domain', priority: 20 },
  '/blacklistdomain': { ruleType: 'blacklist', matchType: 'domain', priority: 20 }
};
const disableMap = {
  '/unwhitelist': { ruleType: 'whitelist', matchType: 'exact_sender' },
  '/unblacklist': { ruleType: 'blacklist', matchType: 'exact_sender' },
  '/unreceipt': { ruleType: 'force_receipts', matchType: 'exact_sender' },
  '/unreview': { ruleType: 'force_review', matchType: 'exact_sender' },
  '/unwhitelistdomain': { ruleType: 'whitelist', matchType: 'domain' },
  '/unblacklistdomain': { ruleType: 'blacklist', matchType: 'domain' }
};
if (upsertMap[command]) {
  const mapped = upsertMap[command];
  const example = mapped.matchType === 'domain' ? 'example.com' : 'email@example.com';
  if (!value) return out({ allowed: true, action: 'reply', replyText: `Missing value. Example: ${command} ${example}` });
  if (mapped.matchType === 'exact_sender' && !validEmail.test(value)) return out({ allowed: true, action: 'reply', replyText: 'Invalid email format.' });
  if (mapped.matchType === 'domain' && !validDomain.test(value.replace(/^@/, ''))) return out({ allowed: true, action: 'reply', replyText: 'Invalid domain format.' });
  return out({ allowed: true, action: 'upsert', senderPattern: mapped.matchType === 'domain' ? value.replace(/^@/, '') : value, matchType: mapped.matchType, ruleType: mapped.ruleType, priority: mapped.priority, notes: `Telegram command ${command}` });
}
if (disableMap[command]) {
  const mapped = disableMap[command];
  const example = mapped.matchType === 'domain' ? 'example.com' : 'email@example.com';
  if (!value) return out({ allowed: true, action: 'reply', replyText: `Missing value. Example: ${command} ${example}` });
  if (mapped.matchType === 'exact_sender' && !validEmail.test(value)) return out({ allowed: true, action: 'reply', replyText: 'Invalid email format.' });
  if (mapped.matchType === 'domain' && !validDomain.test(value.replace(/^@/, ''))) return out({ allowed: true, action: 'reply', replyText: 'Invalid domain format.' });
  return out({ allowed: true, action: 'disable', senderPattern: mapped.matchType === 'domain' ? value.replace(/^@/, '') : value, matchType: mapped.matchType, ruleType: mapped.ruleType });
}
return out({ allowed: true, action: 'reply', replyText: 'Unknown command. Send /help.' });

// Purpose: Format simple replies (help + fallback) for Telegram.
// V2.6: Merged Format Help Reply + Format Generic Reply into one node.
function tg(s) { s = String(s ?? ''); return s.length <= 3900 ? s : s.slice(0, 3900) + '\n\n[...truncated]'; }
return [{ json: { chatId: $json.chatId, account: $json.account || $env.GMAIL_ACCOUNT || 'primary', text: tg($json.replyText || 'Send /help for commands.') } }];

