const rows = $input.all().map(i => i.json || {}).filter(r => r.sender_pattern);
if (!rows.length) return [{ json: { chatId: cmd.chatId, account: cmd.account, text: '📋 <b>Your Gmail Rules</b>

No active rules yet.' } }];
const groups = { whitelist: [], blacklist: [], force_receipts: [], force_review: [] };
for (const r of rows) {
  const line = `• ${h(r.sender_pattern)} <i>(${h(r.match_type)})</i>`;
  if (!groups[r.rule_type]) groups[r.rule_type] = [];
  groups[r.rule_type].push(line);
}
const text = `📋 <b>Your Gmail Rules</b>

` +
  `<b>Whitelist → priority</b>
${groups.whitelist.length ? groups.whitelist.join('
') : 'None'}

` +
  `<b>Blacklist → unimportant</b>
${groups.blacklist.length ? groups.blacklist.join('
') : 'None'}

` +
  `<b>Receipts</b>
${groups.force_receipts.length ? groups.force_receipts.join('
') : 'None'}

` +
  `<b>Please-review</b>
${groups.force_review.length ? groups.force_review.join('
') : 'None'}`;
return [{ json: { chatId: cmd.chatId, account: cmd.account, text: tg(text) } }];

